import{k as e,p as t,u as n}from"./chunks/runtime-core.esm-bundler.PK8HO-US.js";import{t as r}from"./chunks/plugin-vue_export-helper.DrfHhw6c.js";const i=JSON.parse(`{"title":"移植到 26.1 快照版本","description":"移植到 Minecraft 的下一个版本的快照版本的指南。","frontmatter":{"title":"移植到 26.1 快照版本","description":"移植到 Minecraft 的下一个版本的快照版本的指南。","authors":["cassiancc"],"files":[]},"headers":[],"relativePath":"zh_cn/develop/porting/next.md","filePath":"translated/zh_cn/develop/porting/next.md","lastUpdated":1771183440000}`);var a={name:`zh_cn/develop/porting/next.md`};function o(r,i,a,o,s,c){return e(),n(`div`,null,[...i[0]||=[t(`<h1 id="h1" tabindex="-1">移植到 26.1 快照版本 <a class="header-anchor" href="#h1" aria-label="Permalink to “移植到 26.1 快照版本”">​</a></h1><p>即将到来的 Minecraft 的 26.1 版本是未混淆的，其快照也是如此。 知道这一点后，你就需要为你的构建版本做比平时更多的改变，才能移植到新版本。</p><div class="info custom-block"><p class="custom-block-title custom-block-title-default">INFO</p><p>这些文档讨论的是从 <strong>1.21.11</strong> 迁移到 <strong>26.1</strong> 的快照版本， 如果你是要迁移到 <strong>1.21.11</strong>，请参阅 <a href="./current">迁移到 1.21.11</a>。</p></div><p>注意如果你的模组还是在使用 Fabric 的 Yarn 映射，你首先需要<a href="./../migrating-mappings/">将你的模组迁移到 Mojang 的官方映射</a>然后再移植到 26.1。</p><p>如果你是使用的 IntelliJ IDEA，还需要将其更新到 <code>2025.3</code> 以上版本，才有对 Java 25 的完全支持。</p><h2 id="build-script" tabindex="-1">更新构建脚本 <a class="header-anchor" href="#build-script" aria-label="Permalink to “更新构建脚本”">​</a></h2><p>首先将你的模组的 <code>gradle/wrapper/gradle-wrapper.properties</code>、<code>gradle.properties</code> 和 <code>build.gradle</code> 更新到最新版本。</p><ol><li>运行以下命令，将 Gradle 更新到最新版：<code>./gradlew wrapper --gradle-version latest</code></li><li>在 <code>gradle.properties</code>（推荐）或 <code>build.gradle</code> 中找到 Minecraft、Fabric Loader、Fabric Loom 和 Fabric API 的版本。 在 <a href="https://fabricmc.net/develop/" target="_blank" rel="noreferrer">Fabric Develop 网站</a>找到 Fabric 组件的推荐版本。 <ul><li>注意，因为 26.1 的快照不是 Minecraft 的稳定版本，所以你需要从下拉菜单中手动选择此版本。</li></ul></li><li>在 <code>build.gradle</code> 的顶部，将使用的 Loom 的版本，由 <code>id &quot;fabric-loom&quot;</code> 修改为 <code>id &quot;net.fabricmc.fabric-loom&quot;</code>。 如果你是在 <code>settings.gradle</code> 中指定的 Loom，也一并将其更改。</li><li>在 <code>build.gradle</code> 的 dependencies 段中，移除 <code>mappings</code> 的行。</li><li>将任何 <code>modImplementation</code> 或 <code>modCompileOnly</code> 的实例替换为 <code>implementation</code> 和 <code>compileOnly</code>。</li><li>移除任何适用于 26.1 之前的版本的模组，或将其替换为兼容此更新的版本。 <ul><li>1.21.11 或 Minecraft 更早版本的现有模组均不会在 26.1 中生效，即使是仅编译（compile-only）的依赖。</li></ul></li><li>将任何提及 <code>remapJar</code> 的都替换为 <code>jar</code>。</li><li>按 IntelliJ IDEA 右上角的刷新按钮刷新 Gradle。 如果按钮不可见，可运行 <code>./gradlew --refresh-dependencies</code> 以强制清除缓存。</li></ol><h2 id="porting-guides" tabindex="-1">更新代码 <a class="header-anchor" href="#porting-guides" aria-label="Permalink to “更新代码”">​</a></h2><p>构建脚本更新到 26.1 后，现在就可以检查你的模组并更新任何改变的代码，以使其与快照兼容。</p><div class="warning custom-block"><p class="custom-block-title">重要</p><p>因为 Minecraft 26.1 仍在快照阶段，特定的变化的文档仍缺失。 祝你好运，你只能靠自己了！</p></div><ul><li><a href="./26.1/fabric-api">Fabric API 26.1 迁移指南</a>列举了 Fabric API 在 26.1 中为匹配 Mojang 的名称而进行的更名。</li><li><a href="https://zh.minecraft.wiki/w/Java%E7%89%8826.1" target="_blank" rel="noreferrer">Minecraft Wiki 上的《Java版26.1》</a>是此次更新内容的非官方总结。</li><li><a href="https://github.com/ChampionAsh5357/neoforged-github/blob/update/26.1/primers/26.1/index.md" target="_blank" rel="noreferrer">NeoForge 的 <em>Minecraft 1.21.11 -&gt; 26.1 Mod Migration Primer</em></a> 介绍了从 1.21.11 迁移到 26.1，仅聚焦于原版代码的变更。 <ul><li>请注意，链接的文章是第三方材料，不由 Fabric 维护。 其版权属于 @ChampionAsh5357，按 <a href="https://creativecommons.org/licenses/by/4.0/" target="_blank" rel="noreferrer">Creative Commons Attribution 4.0 International</a> 的许可协议发布。</li></ul></li></ul>`,12)]])}var s=r(a,[[`render`,o]]);export{i as __pageData,s as default};